import{_ as a,o as s,c as r,a2 as i}from"./chunks/framework.Cuq8tsM6.js";const v=JSON.parse('{"title":"Découvrir getinside","description":"","frontmatter":{"title":"Découvrir getinside"},"headers":[],"relativePath":"docs/fr/start-here/index.md","filePath":"docs/fr/start-here/index.md"}'),n={name:"docs/fr/start-here/index.md"};function t(o,e,c,d,l,u){return s(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="decouvrir-le-retail-media" tabindex="-1">Découvrir le Retail Media <a class="header-anchor" href="#decouvrir-le-retail-media" aria-label="Permalink to &quot;Découvrir le Retail Media&quot;">​</a></h1><p class="gi-page-intro">Définition des concepts et opportunités pour votre marque — annonceur ou e-commerçant.</p><h2 id="un-ecosysteme-double" tabindex="-1">Un écosystème double <a class="header-anchor" href="#un-ecosysteme-double" aria-label="Permalink to &quot;Un écosystème double&quot;">​</a></h2><div class="gi-format-grid"><div class="gi-format-card"><span class="gi-format-card-icon">🛍️</span><span class="gi-format-card-title">Pour les Annonceurs</span><p class="gi-format-card-desc">Toucher des acheteurs avérés au cœur de leur expérience d&#39;achat, via la recommandation d&#39;une marque tiers.</p></div><div class="gi-format-card"><span class="gi-format-card-icon">📦</span><span class="gi-format-card-title">Pour les E-commerçants</span><p class="gi-format-card-desc">Transformer vos centres de coûts (Logistique, CRM) en centres de profits en monétisant vos actifs.</p></div></div><div class="gi-accent-box"><strong>🔄 Le Modèle getinside : Monétiser pour Réinvestir</strong><p>La force de la plateforme réside dans la fluidité entre vos revenus et vos dépenses.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>1. Gagnez</strong><p>Monétisez vos colis et emails sortants.</p></div><div class="gi-value-card"><strong>2. Financez</strong><p>Utilisez ce solde (Wallet) sans sortir de trésorerie.</p></div><div class="gi-value-card"><strong>3. Croissez</strong><p>Achetez du trafic qualifié pour votre propre site.</p></div></div></div><h2 id="un-ecosysteme-complet" tabindex="-1">Un écosystème complet <a class="header-anchor" href="#un-ecosysteme-complet" aria-label="Permalink to &quot;Un écosystème complet&quot;">​</a></h2><div class="gi-nav-list"><a href="../advertisers/sponsored-mail" class="gi-nav-card"><span class="gi-nav-card-icon">📦</span><div class="gi-nav-card-body"><p class="gi-nav-card-title">L&#39;Insertion Colis (Physique)</p><p class="gi-nav-card-desc">Glissez un flyer dans le colis. <strong>L&#39;atout :</strong> 100% de taux d&#39;ouverture et prise en main physique.</p></div><span class="gi-nav-card-arrow">→</span></a><a href="../advertisers/dedicated-email" class="gi-nav-card"><span class="gi-nav-card-icon">📧</span><div class="gi-nav-card-body"><p class="gi-nav-card-title">L&#39;Emailing (Digital)</p><p class="gi-nav-card-desc">Une marque partenaire recommande vos produits à sa base. <strong>L&#39;atout :</strong> Puissance de l&#39;endorsement et du volume.</p></div><span class="gi-nav-card-arrow">→</span></a><a href="../advertisers/sponsored-social" class="gi-nav-card"><span class="gi-nav-card-icon">📱</span><div class="gi-nav-card-body"><p class="gi-nav-card-title">Social Ads (Influence)</p><p class="gi-nav-card-desc">Diffusez via les comptes sociaux (Insta/TikTok) des retailers. <strong>L&#39;atout :</strong> Crédibilité de la marque hôte.</p></div><span class="gi-nav-card-arrow">→</span></a><a href="../advertisers/co-branded-contest" class="gi-nav-card"><span class="gi-nav-card-icon">🎁</span><div class="gi-nav-card-body"><p class="gi-nav-card-title">Jeu Concours (Lead Gen)</p><p class="gi-nav-card-desc">Collectez des emails qualifiés via une mécanique ludique. <strong>L&#39;atout :</strong> Enrichissement rapide de votre base CRM.</p></div><span class="gi-nav-card-arrow">→</span></a></div><h2 id="la-valeur-ajoutee-de-la-plateforme" tabindex="-1">La Valeur Ajoutée de la Plateforme <a class="header-anchor" href="#la-valeur-ajoutee-de-la-plateforme" aria-label="Permalink to &quot;La Valeur Ajoutée de la Plateforme&quot;">​</a></h2><p>getinside agit comme un tiers de confiance pour sécuriser et fluidifier les échanges.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>🤝 Centralisation</strong><p>Un seul contrat et une seule facturation pour accéder à +250 partenaires.</p></div><div class="gi-value-card"><strong>🛡️ Sécurité Financière</strong><p>Les fonds sont sécurisés avant le lancement. Éditeur et annonceur sont protégés.</p></div><div class="gi-value-card"><strong>⚙️ Tech &amp; Logistique</strong><p>Impression, routage, tracking, RGPD... Nous absorbons la complexité pour vous.</p></div></div><h2 id="l-excellence-operationnelle" tabindex="-1">L&#39;Excellence Opérationnelle <a class="header-anchor" href="#l-excellence-operationnelle" aria-label="Permalink to &quot;L&#39;Excellence Opérationnelle&quot;">​</a></h2><p>La confiance des annonceurs se gagne sur l&#39;<strong>exécution sans faille</strong>.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>⚡ Réactivité = Confiance</strong><p>Les processus standardisés rassurent les grandes marques.</p></div><div class="gi-value-card"><strong>✅ Zéro Erreur = Brand Safety</strong><p>Le respect strict des workflows garantit l&#39;image de marque de l&#39;annonceur.</p></div><div class="gi-value-card"><strong>📈 Data Fiable = Renouvellement</strong><p>Un tracking fiable prouve le ROI — condition sine qua non pour qu&#39;un annonceur re-signe.</p></div></div><div class="gi-danger-box"><strong>⚠️ Impact direct sur vos revenus</strong><p>Notre algorithme prend en compte votre fiabilité historique. Des manquements (retards, tracking défaillant) réduisent votre <strong>score de qualité</strong> et vos chances de recevoir de futures campagnes.</p></div>',14)])])}const g=a(n,[["render",t]]);export{v as __pageData,g as default};
